import { describe, it } from "vitest";

describe("Game of Life - nextGeneration", () => {
  // 1. Simplest case
  it.todo("should return empty array when given an empty array");

  // 2. Individual rules in isolation (Single cells, underpopulation, survival, overpopulation, reproduction)
  it.todo("should return empty array when a single cell dies -- Gen 0: [(0,0)] -> Gen 1: []");

  it.todo("should die due to underpopulation with fewer than 2 live neighbors -- Gen 0: [(0,1), (1,1)] -> Gen 1: []");

  it.todo("should survive with 2 live neighbors -- Gen 0: [(0,0), (1,0), (0,1)] (cells [(0,0), (1,0), (0,1)] each have 2 neighbors) -> Gen 1: should contain original cells plus the reproduction of (1,1)");

  it.todo("should survive with 3 live neighbors (Rule 2) -- Gen 0 center (1,1) has 3 live neighbors in [(1,0), (0,1), (2,1), (1,1)] -> Gen 1 (1,1) survives");

  it.todo("should die due to overpopulation with more than 3 live neighbors (Rule 3) -- Gen 0 center (1,1) has 4 live neighbors in [(1,1), (0,1), (2,1), (1,0), (1,2)] -> Gen 1 (1,1) dies");

  it.todo("should reproduce when a dead cell has exactly 3 live neighbors (Rule 4) -- Gen 0: [(0,0), (1,0), (0,1)] -> Gen 1: dead cell (1,1) has 3 neighbors -> (1,1) becomes alive");

  // 3. Pattern Examples from Specification
  it.todo("should correctly evolve a Blinker pattern -- Gen 0: [(0,0), (0,1), (0,2)] -> Gen 1: [(-1,1), (0,1), (1,1)]");

  it.todo("should correctly remain stable for a Block pattern (still life) -- Gen 0: [(0,0), (1,0), (0,1), (1,1)] -> Gen 1: [(0,0), (1,0), (0,1), (1,1)]");
});

